/**
 * FACULTY OF TECHNOLOGY - BIRTHDAY GRAPHIC GENERATOR
 * CORE ENGINE & CANVAS COMPOSITOR (CanvaStudent Font Edition)
 * 
 * This script manages the static state, handles files drag-and-drop,
 * implements mouse/touch canvas panning, handles Google Font checking,
 * and compiles complex graphic layers into a high-DPI downloadable graphic.
 * 
 * Author: Canvas API Expert & Senior Frontend Engineer
 */

// ==========================================
// 1. DEVELOPER CONFIGURATION OBJECT (EXACT)
// ==========================================
const CONFIG = {
    canvasWidth: 1080,
    canvasHeight: 1512,
    circle: {
        centerX: 540,
        centerY: 630,
        radius: 225 
    },
    text: {
        centerX: 540,
        centerY: 955,
        fontSize: 106,
        fontFamily: "CanvaStudent", 
        color: "#FFFFFF"
    }
};

const SYSTEM_SETTINGS = {
    templateSrc: 'data:image/jpeg;base64,',
    maxParticles: 35
};

// ==========================================
// 2. STATE MANAGEMENT
// ==========================================
const State = {
    // Graphic inputs
    uploadedImage: null,  // Holds the Image DOM object of the user photo
    userName: '',          // Student name

    // Transform parameters (Photo inside mask)
    zoom: 1.0,            // Managed by Zoom Slider (min 0.5, max 2.0)
    offsetX: 0,           // Free horizontal dragging inside canvas
    offsetY: 0,           // Managed by Y-Offset Slider & vertical dragging

    // Active Calibration Values (synced with CONFIG initially, bound to Admin sliders)
    circleX: CONFIG.circle.centerX,
    circleY: CONFIG.circle.centerY,
    circleRadius: CONFIG.circle.radius,
    textY: CONFIG.text.centerY,
    fontSize: CONFIG.text.fontSize,

    // Canvas interaction flags
    isDragging: false,
    dragStartX: 0,
    dragStartY: 0,

    // Background asset caching
    templateImage: null,
    isTemplateLoaded: false
};

// ==========================================
// 3. DOM ELEMENT REFERENCES
// ==========================================
const elements = {
    canvas: document.getElementById('birthdayCanvas'),
    ctx: document.getElementById('birthdayCanvas').getContext('2d'),

    // Controls
    fileInput: document.getElementById('fileInput'),
    dropZone: document.getElementById('dropZone'),
    uploadPreview: document.getElementById('uploadPreview'),
    thumbnailImg: document.getElementById('thumbnailImg'),
    fileNameText: document.getElementById('fileNameText'),
    removePhotoBtn: document.getElementById('removePhotoBtn'),
    nameInput: document.getElementById('nameInput'),

    // Sliders
    zoomSlider: document.getElementById('zoomSlider'),
    zoomVal: document.getElementById('zoomVal'),
    yOffsetSlider: document.getElementById('yOffsetSlider'),
    yOffsetVal: document.getElementById('yOffsetVal'),
    resetPhotoPosBtn: document.getElementById('resetPhotoPosBtn'),

    // Admin Calibration sliders
    circleXSlider: document.getElementById('circleXSlider'),
    circleXVal: document.getElementById('circleXVal'),
    circleYSlider: document.getElementById('circleYSlider'),
    circleYVal: document.getElementById('circleYVal'),
    circleRadiusSlider: document.getElementById('circleRadiusSlider'),
    circleRadiusVal: document.getElementById('circleRadiusVal'),
    textYSlider: document.getElementById('textYSlider'),
    textYVal: document.getElementById('textYVal'),
    fontSizeSlider: document.getElementById('fontSizeSlider'),
    fontSizeVal: document.getElementById('fontSizeVal'),
    copyConfigBtn: document.getElementById('copyConfigBtn'),
    fineTuneToggle: document.getElementById('fineTuneToggle'),
    fineTuneContent: document.getElementById('fineTuneContent'),

    // Global Action triggers
    downloadBtn: document.getElementById('downloadBtn'),
    shareWhatsappBtn: document.getElementById('shareWhatsappBtn'),
    toast: document.getElementById('toast'),
    toastMessage: document.getElementById('toastMessage'),
    sparklesContainer: document.getElementById('sparklesContainer')
};

// ==========================================
// 4. INITIALIZATION & SETUP
// ==========================================
document.addEventListener('DOMContentLoaded', () => {
    initApp();
});

function initApp() {
    // Create UI Background sparkles
    createFloatingParticles();
    
    // Hook up interface event listeners
    setupEventListeners();
    
    // Populate sliders with CONFIG values
    syncSlidersFromState();
    
    // Robust parallel loading using Promise.all to ensure template & font are loaded
    loadAssetsAndStart();
}

/**
 * Creates floating golden particle elements in the document background.
 */
function createFloatingParticles() {
    for (let i = 0; i < SYSTEM_SETTINGS.maxParticles; i++) {
        const particle = document.createElement('div');
        particle.classList.add('sparkle');
        
        // Randomize placements, delays, scales and horizontal drifts
        const size = Math.random() * 6 + 2; // size in px
        const left = Math.random() * 100; // start left %
        const delay = Math.random() * 8; // delay in seconds
        const duration = Math.random() * 10 + 6; // duration in seconds
        const drift = Math.random() * 80 - 40; // horizontal drift px
        const opacity = Math.random() * 0.4 + 0.15; // max opacity
        
        particle.style.width = `${size}px`;
        particle.style.height = `${size}px`;
        particle.style.left = `${left}%`;
        particle.style.setProperty('--delay', `${delay}s`);
        particle.style.setProperty('--duration', `${duration}s`);
        particle.style.setProperty('--drift', `${drift}px`);
        particle.style.setProperty('--scale', Math.random() * 0.8 + 0.4);
        particle.style.setProperty('--max-opacity', opacity);
        
        elements.sparklesContainer.appendChild(particle);
    }
}

/**
 * Robust Asset Loading: Loads background image and custom font face CanvaStudent in parallel.
 */
function loadAssetsAndStart() {
    // 1. Font Face loading promise
    const fontPromise = document.fonts.load(`90px ${CONFIG.text.fontFamily}`)
        .then(loadedFonts => {
            console.log('Font loaded:', loadedFonts);
        })
        .catch(err => {
            console.warn('Custom CanvaStudent font load failed, employing system fallback:', err);
        });

    // 2. Background Image loading promise
    const imagePromise = new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => resolve(img);
        img.onerror = () => reject(new Error('Failed to load base_template.png'));
        img.src = SYSTEM_SETTINGS.templateSrc;
    });

    // 3. Coordinate loads and trigger canvas render for first time
    Promise.all([fontPromise, imagePromise])
        .then(([_, img]) => {
            State.templateImage = img;
            State.isTemplateLoaded = true;
            requestDraw();
        })
        .catch(err => {
            console.error('Robust asset loading completed with errors:', err);
            // Fallback draw
            requestDraw();
        });
}

/**
 * Asserts all slider DOM positions match State properties.
 */
function syncSlidersFromState() {
    // Standard photo sliders
    elements.zoomSlider.value = State.zoom;
    elements.zoomVal.innerText = `${State.zoom.toFixed(2)}x`;

    elements.yOffsetSlider.value = State.offsetY;
    elements.yOffsetVal.innerText = `${State.offsetY}px`;

    // Admin calibration sliders
    elements.circleXSlider.value = State.circleX;
    elements.circleXVal.innerText = `${State.circleX}px`;
    
    elements.circleYSlider.value = State.circleY;
    elements.circleYVal.innerText = `${State.circleY}px`;
    
    elements.circleRadiusSlider.value = State.circleRadius;
    elements.circleRadiusVal.innerText = `${State.circleRadius}px`;
    
    elements.textYSlider.value = State.textY;
    elements.textYVal.innerText = `${State.textY}px`;
    
    elements.fontSizeSlider.value = State.fontSize;
    elements.fontSizeVal.innerText = `${State.fontSize}px`;
}

// ==========================================
// 5. EVENT LISTENERS
// ==========================================
function setupEventListeners() {
    // Student Name Input
    elements.nameInput.addEventListener('input', (e) => {
        State.userName = e.target.value;
        requestDraw();
    });
    
    // Zoom/Scale Slider (min 0.5, max 2.0)
    elements.zoomSlider.addEventListener('input', (e) => {
        State.zoom = parseFloat(e.target.value);
        elements.zoomVal.innerText = `${State.zoom.toFixed(2)}x`;
        requestDraw();
    });
    
    // Y-Offset Slider (min -200, max 200)
    elements.yOffsetSlider.addEventListener('input', (e) => {
        State.offsetY = parseInt(e.target.value);
        elements.yOffsetVal.innerText = `${State.offsetY}px`;
        requestDraw();
    });
    
    // Reset Position Button
    elements.resetPhotoPosBtn.addEventListener('click', () => {
        State.zoom = 1.0;
        State.offsetX = 0;
        State.offsetY = 0;
        elements.zoomSlider.value = 1.0;
        elements.zoomVal.innerText = '1.00x';
        elements.yOffsetSlider.value = 0;
        elements.yOffsetVal.innerText = '0px';
        requestDraw();
        showToast('Photo position and scale reset!');
    });
    
    // Drag and Drop Zone Click triggers Hidden File Input
    elements.dropZone.addEventListener('click', (e) => {
        if (e.target.closest('#removePhotoBtn')) return;
        elements.fileInput.click();
    });
    
    elements.fileInput.addEventListener('change', (e) => {
        if (e.target.files.length > 0) {
            handleUploadedFile(e.target.files[0]);
        }
    });
    
    // Drag-Over visual styles for DropZone
    ['dragenter', 'dragover'].forEach(eventName => {
        elements.dropZone.addEventListener(eventName, (e) => {
            e.preventDefault();
            e.stopPropagation();
            elements.dropZone.classList.add('dragover');
        }, false);
    });
    
    ['dragleave', 'drop'].forEach(eventName => {
        elements.dropZone.addEventListener(eventName, (e) => {
            e.preventDefault();
            e.stopPropagation();
            elements.dropZone.classList.remove('dragover');
        }, false);
    });
    
    elements.dropZone.addEventListener('drop', (e) => {
        const dt = e.dataTransfer;
        const files = dt.files;
        if (files.length > 0) {
            handleUploadedFile(files[0]);
        }
    });
    
    // Remove Photo Button
    elements.removePhotoBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        removeProfilePhoto();
    });
    
    // Canvas dragging handler
    setupCanvasDragging();
    
    // Fine-Tuning Accordion
    elements.fineTuneToggle.addEventListener('click', () => {
        const parent = elements.fineTuneToggle.parentElement;
        parent.classList.toggle('active');
    });
    
    // Calibration sliders bound to state variables
    elements.circleXSlider.addEventListener('input', (e) => {
        State.circleX = parseInt(e.target.value);
        elements.circleXVal.innerText = `${State.circleX}px`;
        requestDraw();
    });
    
    elements.circleYSlider.addEventListener('input', (e) => {
        State.circleY = parseInt(e.target.value);
        elements.circleYVal.innerText = `${State.circleY}px`;
        requestDraw();
    });
    
    elements.circleRadiusSlider.addEventListener('input', (e) => {
        State.circleRadius = parseInt(e.target.value);
        elements.circleRadiusVal.innerText = `${State.circleRadius}px`;
        requestDraw();
    });
    
    elements.textYSlider.addEventListener('input', (e) => {
        State.textY = parseInt(e.target.value);
        elements.textYVal.innerText = `${State.textY}px`;
        requestDraw();
    });
    
    elements.fontSizeSlider.addEventListener('input', (e) => {
        State.fontSize = parseInt(e.target.value);
        elements.fontSizeVal.innerText = `${State.fontSize}px`;
        requestDraw();
    });
    
    // Copy tuned CONFIG button
    elements.copyConfigBtn.addEventListener('click', () => {
        const configText = `// Tuned configuration matching vertical template layout
const CONFIG = {
    canvasWidth: ${CONFIG.canvasWidth},
    canvasHeight: ${CONFIG.canvasHeight},
    circle: {
        centerX: ${State.circleX},
        centerY: ${State.circleY},
        radius: ${State.circleRadius}
    },
    text: {
        centerX: ${CONFIG.text.centerX},
        centerY: ${State.textY},
        fontSize: ${State.fontSize},
        fontFamily: "${CONFIG.text.fontFamily}", 
        color: "${CONFIG.text.color}"
    }
};`;
        
        navigator.clipboard.writeText(configText)
            .then(() => {
                showToast('CONFIG copied! Paste it at the top of script.js.');
            })
            .catch(err => {
                console.error('Failed to copy config: ', err);
                showToast('Failed to copy config.');
            });
    });
    
    // Download Graphic Trigger
    elements.downloadBtn.addEventListener('click', triggerDownload);
    
    // WhatsApp Share Trigger
    elements.shareWhatsappBtn.addEventListener('click', triggerShareWhatsapp);
}

// ==========================================
// 6. PHOTO FILE PROCESSING
// ==========================================
function handleUploadedFile(file) {
    if (!file.type.match('image.*')) {
        showToast('Error: Please upload a valid image file');
        return;
    }
    
    const reader = new FileReader();
    reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
            State.uploadedImage = img;
            
            // Show preview thumbnail in dropzone
            elements.thumbnailImg.src = e.target.result;
            elements.fileNameText.innerText = file.name;
            
            // Switch prompt view to preview view
            elements.dropZone.querySelector('.upload-prompt').style.display = 'none';
            elements.uploadPreview.style.display = 'flex';
            
            // Reset position
            State.zoom = 1.0;
            State.offsetX = 0;
            State.offsetY = 0;
            elements.zoomSlider.value = 1.0;
            elements.zoomVal.innerText = '1.00x';
            elements.yOffsetSlider.value = 0;
            elements.yOffsetVal.innerText = '0px';
            
            requestDraw();
            showToast('Student photo loaded!');
        };
        img.src = e.target.result;
    };
    reader.readAsDataURL(file);
}

function removeProfilePhoto() {
    State.uploadedImage = null;
    elements.fileInput.value = '';
    
    // Switch view back to prompt
    elements.uploadPreview.style.display = 'none';
    elements.dropZone.querySelector('.upload-prompt').style.display = 'block';
    
    requestDraw();
    showToast('Photo removed.');
}

// ==========================================
// 7. CANVAS DRAG-TO-PAN CONTROLS
// ==========================================
/**
 * Direct Canvas mouse and touch drag panning.
 */
function setupCanvasDragging() {
    // Mouse events
    elements.canvas.addEventListener('mousedown', (e) => {
        if (!State.uploadedImage) return;
        State.isDragging = true;
        const coords = getCanvasRelativeCoords(e);
        State.dragStartX = coords.x;
        State.dragStartY = coords.y;
    });
    
    window.addEventListener('mousemove', (e) => {
        if (!State.isDragging || !State.uploadedImage) return;
        const coords = getCanvasRelativeCoords(e);
        
        const dx = coords.x - State.dragStartX;
        const dy = coords.y - State.dragStartY;
        
        // Update offsets
        State.offsetX += dx;
        State.offsetY += dy;
        
        // Bounded constraint checks for Y offset to stay within slider limits
        if (State.offsetY > 200) State.offsetY = 200;
        if (State.offsetY < -200) State.offsetY = -200;
        
        // Sync Y-offset specifically to Y-offset range slider (X dragging is fully free)
        elements.yOffsetSlider.value = State.offsetY;
        elements.yOffsetVal.innerText = `${State.offsetY}px`;
        
        State.dragStartX = coords.x;
        State.dragStartY = coords.y;
        
        requestDraw();
    });
    
    window.addEventListener('mouseup', () => {
        State.isDragging = false;
    });
    
    // Touch events for mobile screens
    elements.canvas.addEventListener('touchstart', (e) => {
        if (!State.uploadedImage || e.touches.length === 0) return;
        State.isDragging = true;
        const touch = e.touches[0];
        const coords = getCanvasRelativeCoords(touch);
        State.dragStartX = coords.x;
        State.dragStartY = coords.y;
        e.preventDefault();
    }, { passive: false });
    
    elements.canvas.addEventListener('touchmove', (e) => {
        if (!State.isDragging || !State.uploadedImage || e.touches.length === 0) return;
        const touch = e.touches[0];
        const coords = getCanvasRelativeCoords(touch);
        
        const dx = coords.x - State.dragStartX;
        const dy = coords.y - State.dragStartY;
        
        State.offsetX += dx;
        State.offsetY += dy;
        
        if (State.offsetY > 200) State.offsetY = 200;
        if (State.offsetY < -200) State.offsetY = -200;
        
        elements.yOffsetSlider.value = State.offsetY;
        elements.yOffsetVal.innerText = `${State.offsetY}px`;
        
        State.dragStartX = coords.x;
        State.dragStartY = coords.y;
        
        requestDraw();
        e.preventDefault();
    }, { passive: false });
    
    elements.canvas.addEventListener('touchend', () => {
        State.isDragging = false;
    });
}

/**
 * Scale relative coordinates from viewport screen size to 1080x1512 backing space.
 */
function getCanvasRelativeCoords(eventOrTouch) {
    const rect = elements.canvas.getBoundingClientRect();
    
    const scaleX = CONFIG.canvasWidth / rect.width;
    const scaleY = CONFIG.canvasHeight / rect.height;
    
    return {
        x: (eventOrTouch.clientX - rect.left) * scaleX,
        y: (eventOrTouch.clientY - rect.top) * scaleY
    };
}

// ==========================================
// 8. GRAPHIC COMPOSITING ENGINE
// ==========================================
let drawPending = false;
function requestDraw() {
    if (!drawPending) {
        drawPending = true;
        requestAnimationFrame(() => {
            drawCanvas();
            drawPending = false;
        });
    }
}

/**
 * Renders the High-DPI canvas layers
 * Draw order: Background -> Masked Photo -> Gold Ring border -> Glowing Name
 */
function drawCanvas() {
    const ctx = elements.ctx;
    const w = CONFIG.canvasWidth;
    const h = CONFIG.canvasHeight;
    
    ctx.clearRect(0, 0, w, h);
    
    // ----------------------------------------------------
    // LAYER 1 (Background): Draw base_template.png
    // ----------------------------------------------------
    if (State.isTemplateLoaded && State.templateImage) {
        ctx.drawImage(State.templateImage, 0, 0, w, h);
    } else {
        // Fallback procedural background template if file missing
        drawFallbackProceduralBackground(ctx, w, h);
    }
    
    // ----------------------------------------------------
    // LAYER 2 (User Photo & Mask)
    // ----------------------------------------------------
    if (State.uploadedImage) {
        ctx.save();
        
        ctx.beginPath();
        ctx.arc(State.circleX, State.circleY, State.circleRadius, 0, Math.PI * 2);
        ctx.clip();
        
        // Cover aspect cover math calculations (like object-fit: cover)
        const img = State.uploadedImage;
        const targetSize = State.circleRadius * 2;
        
        const wRatio = targetSize / img.width;
        const hRatio = targetSize / img.height;
        const baseRatio = Math.max(wRatio, hRatio);
        
        // Final scale (including zoom slider)
        const finalScale = baseRatio * State.zoom;
        const drawW = img.width * finalScale;
        const drawH = img.height * finalScale;
        
        // Apply vertical (Y-offset) and horizontal offsets
        const drawX = State.circleX - (drawW / 2) + State.offsetX;
        const drawY = State.circleY - (drawH / 2) + State.offsetY;
        
        ctx.drawImage(img, drawX, drawY, drawW, drawH);
        
        ctx.restore();
    } else {
        // Circular placeholder when empty
        ctx.save();
        ctx.beginPath();
        ctx.arc(State.circleX, State.circleY, State.circleRadius, 0, Math.PI * 2);
        ctx.clip();
        
        // Inner charcoal background circle
        ctx.fillStyle = '#101218';
        ctx.fillRect(State.circleX - State.circleRadius, State.circleY - State.circleRadius, State.circleRadius * 2, State.circleRadius * 2);
        
        // Subtle dotted concentric inner line
        ctx.strokeStyle = 'rgba(196, 155, 61, 0.2)';
        ctx.lineWidth = 3;
        ctx.setLineDash([6, 6]);
        ctx.beginPath();
        ctx.arc(State.circleX, State.circleY, State.circleRadius - 15, 0, Math.PI * 2);
        ctx.stroke();
        ctx.setLineDash([]);
        
        // Camera placeholder icon
        ctx.fillStyle = 'rgba(196, 155, 61, 0.45)';
        ctx.font = '700 56px "Font Awesome 6 Free"';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('\uf03e', State.circleX, State.circleY - 15);
        
        ctx.fillStyle = 'rgba(255, 255, 255, 0.35)';
        ctx.font = '600 18px "Montserrat"';
        ctx.fillText('NO PHOTO UPLOADED', State.circleX, State.circleY + 35);
        ctx.restore();
    }
    
    // ----------------------------------------------------
    // LAYER 3 (Thick Gold Ring)
    // ----------------------------------------------------
    ctx.save();
    ctx.beginPath();
    ctx.arc(State.circleX, State.circleY, State.circleRadius, 0, Math.PI * 2);
    ctx.strokeStyle = '#c49b3d';
    ctx.lineWidth = 10;
    
    // Elegant ring shadow
    ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
    ctx.shadowBlur = 10;
    ctx.shadowOffsetY = 4;
    
    ctx.stroke();
    ctx.restore();
    
    // ----------------------------------------------------
    // LAYER 4 (Glowing Typography)
    // ----------------------------------------------------
    if (State.userName.trim() !== '') {
        ctx.save();
        
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.font = `${State.fontSize}px "${CONFIG.text.fontFamily}"`;
        ctx.fillStyle = '#FFFFFF';
        
        // Glow Effect shadow
        ctx.shadowColor = '#FFFFFF';
        ctx.shadowBlur = 22;
        
        // Auto-scale fonts to guarantee name doesn't clip bounds
        const maxTextWidth = w - 160;
        let activeSize = State.fontSize;
        let measuredWidth = ctx.measureText(State.userName).width;
        
        while (measuredWidth > maxTextWidth && activeSize > 20) {
            activeSize -= 1;
            ctx.font = `${activeSize}px "${CONFIG.text.fontFamily}"`;
            measuredWidth = ctx.measureText(State.userName).width;
        }
        
        ctx.fillText(State.userName, CONFIG.text.centerX, State.textY);
        
        ctx.restore();
    } else {
        // Layout placeholder when empty
        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
        ctx.font = 'italic 500 28px "Montserrat"';
        ctx.fillText('[ Enter Student Name ]', CONFIG.text.centerX, State.textY);
        ctx.restore();
    }
}

/**
 * Procedurally render a high-quality fallback canvas frame.
 */
function drawFallbackProceduralBackground(ctx, w, h) {
    // Charcoal radial backdrop gradient
    const bgGrad = ctx.createRadialGradient(w/2, h/2, 200, w/2, h/2, h);
    bgGrad.addColorStop(0, '#151720');
    bgGrad.addColorStop(1, '#07080b');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, w, h);
    
    // Corner flourishes and double borders
    ctx.strokeStyle = 'rgba(196, 155, 61, 0.25)';
    ctx.lineWidth = 2;
    ctx.strokeRect(50, 50, w - 100, h - 100);
    ctx.strokeRect(60, 60, w - 120, h - 120);
    
    ctx.fillStyle = '#c49b3d';
    ctx.font = 'bold 36px "Montserrat"';
    ctx.textAlign = 'center';
    ctx.fillText('FACULTY OF TECHNOLOGY', w / 2, 95);
    
    ctx.strokeStyle = 'rgba(196, 155, 61, 0.2)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(w/2 - 150, h - 110);
    ctx.lineTo(w/2 + 150, h - 110);
    ctx.stroke();
    
    ctx.fillStyle = '#ffffff';
    ctx.font = '600 18px "Montserrat"';
    ctx.fillText('CONGRATULATIONS STUDENT', w / 2, h - 80);
}

// ==========================================
// 9. HIGH-RES PNG EXPORT LOGIC
// ==========================================
function triggerDownload() {
    const btn = elements.downloadBtn;
    const textSpan = btn.querySelector('.btn-text-content');
    const loaderDiv = btn.querySelector('.download-loader');
    
    btn.disabled = true;
    textSpan.style.display = 'none';
    loaderDiv.style.display = 'flex';
    
    // Brief timer for UI feel and loading response
    setTimeout(() => {
        try {
            drawCanvas();
            
            // Export data to PNG (crystal clear)
            const dataUrl = elements.canvas.toDataURL('image/png', 1.0);
            
            const downloadLink = document.createElement('a');
            const cleanedName = State.userName.trim()
                ? State.userName.toLowerCase().replace(/[^a-z0-9]/g, '-')
                : 'student-graphic';
            downloadLink.download = `${cleanedName}.png`;
            downloadLink.href = dataUrl;
            
            document.body.appendChild(downloadLink);
            downloadLink.click();
            document.body.removeChild(downloadLink);
            
            showToast('High-Res Poster downloaded successfully!');
        } catch (err) {
            console.error('Export Failed:', err);
            showToast('Error: Failed to export Canvas data.');
        } finally {
            btn.disabled = false;
            textSpan.style.display = 'block';
            loaderDiv.style.display = 'none';
        }
    }, 700);
}

// ==========================================
// 10. NOTIFICATION SYSTEM
// ==========================================
let toastTimer = null;
function showToast(message) {
    elements.toastMessage.innerText = message;
    elements.toast.classList.add('show');
    
    if (toastTimer) clearTimeout(toastTimer);
    toastTimer = setTimeout(() => {
        elements.toast.classList.remove('show');
    }, 3500);
}

// ==========================================
// 11. WHATSAPP SHARE & DESKTOP FALLBACK
// ==========================================
/**
 * Compiles dynamic celebratory greeting text with custom emojis.
 */
function getDynamicText(name) {
    const studentName = name.trim() || "Celebrant";
    return `Happy Birthday, ${studentName}! 🎉\nWishing you strength, joy, and amazing opportunities ahead. Keep shining bright! ✨`;
}

/**
 * Executes mobile native Web Share API or falls back to desktop download + clipboard copy + WhatsApp Web.
 */
function triggerShareWhatsapp() {
    const btn = elements.shareWhatsappBtn;
    const contentSpan = btn.querySelector('.btn-share-content');
    const loaderDiv = btn.querySelector('.share-loader');
    
    btn.disabled = true;
    contentSpan.style.display = 'none';
    loaderDiv.style.display = 'flex';
    
    // Ensure graphics are updated
    drawCanvas();
    
    const dynamicText = getDynamicText(State.userName);
    
    // Convert to Blob for Web Share compatibility (type JPEG)
    elements.canvas.toBlob((blob) => {
        if (!blob) {
            console.error('Blob generation failed');
            showToast('Error: Failed to process canvas data.');
            resetShareButton();
            return;
        }
        
        const file = new File([blob], 'birthday.jpg', { type: 'image/jpeg' });
        
        // Mobile-First Check: Web Share API file capability check
        if (navigator.canShare && navigator.canShare({ files: [file] })) {
            navigator.share({
                title: 'Happy Birthday',
                text: dynamicText,
                files: [file]
            })
            .then(() => {
                showToast('Shared successfully on WhatsApp!');
                resetShareButton();
            })
            .catch((err) => {
                console.log('Native share canceled/failed:', err);
                resetShareButton();
            });
        } else {
            // Desktop Fallback
            // a) Trigger local JPEG download
            triggerImageDownloadFallback((dataUrl) => {
                // b) Copy caption text to clipboard
                navigator.clipboard.writeText(dynamicText)
                    .then(() => {
                        // c) Show instruction toast
                        showToast('Image saved & caption copied! Opening WhatsApp Web...');
                        
                        // d) Open WhatsApp Web link in new window tab
                        setTimeout(() => {
                            const url = `https://api.whatsapp.com/send?text=${encodeURIComponent(dynamicText)}`;
                            window.open(url, '_blank');
                            resetShareButton();
                        }, 1000);
                    })
                    .catch(err => {
                        console.error('Clipboard copy failed:', err);
                        showToast('Error: Failed to copy text to clipboard.');
                        resetShareButton();
                    });
            });
        }
    }, 'image/jpeg', 0.92);
    
    function resetShareButton() {
        btn.disabled = false;
        contentSpan.style.display = 'block';
        loaderDiv.style.display = 'none';
    }
}

/**
 * Direct file-export fallback saving a JPEG representation.
 */
function triggerImageDownloadFallback(callback) {
    try {
        const dataUrl = elements.canvas.toDataURL('image/jpeg', 0.9);
        const downloadLink = document.createElement('a');
        
        const cleanedName = State.userName.trim()
            ? State.userName.toLowerCase().replace(/[^a-z0-9]/g, '-')
            : 'student-graphic';
        downloadLink.download = `${cleanedName}.jpg`;
        downloadLink.href = dataUrl;
        
        document.body.appendChild(downloadLink);
        downloadLink.click();
        document.body.removeChild(downloadLink);
        
        if (callback) callback(dataUrl);
    } catch (err) {
        console.error('Fallback image download failed:', err);
        showToast('Error: Failed to compile image.');
    }
}
